final class BoundaryContractChain {

	private final QueryModelNode[] nodes;
	private final BoundaryContract[] contracts;

	private BoundaryContractChain(QueryModelNode[] nodes, BoundaryContract[] contracts) {
		this.nodes = nodes;
		this.contracts = contracts;
	}

	static BoundaryContractChain capture(ScopeAnalysis analysis, QueryModelNode boundary) {
		int count = 0;
		for (QueryModelNode node = boundary; node != null; node = node.getParentNode()) {
			count++;
		}
		QueryModelNode[] nodes = new QueryModelNode[count];
		BoundaryContract[] contracts = new BoundaryContract[count];
		QueryModelNode node = boundary;
		for (int index = 0; index < count; index++) {
			nodes[index] = node;
			contracts[index] = BoundaryContract.capture(analysis, node);
			node = node.getParentNode();
		}
		return new BoundaryContractChain(nodes, contracts);
	}

	int size() {
		return contracts.length;
	}

	BoundaryDifference compare(ScopeAnalysis analysis, QueryModelNode replacement) {
		for (int index = 0; index < contracts.length; index++) {
			QueryModelNode node = index == 0 ? replacement : nodes[index];
			BoundaryDifference difference = contracts[index].compare(BoundaryContract.capture(analysis, node));
			if (difference != null) {
				return new BoundaryDifference("ancestor[" + index + "]." + difference.field(), difference.before(),
						difference.after(), difference.fingerprintMatched());
			}
		}
		return null;
	}
}

final class TransactionalTreeEditor {

	private final QueryModelNode original;
	private final QueryModelNode originalParent;
	private final NodeArena arena;
	private final int boundaryOrigin;
	private QueryModelNode replacement;
	private boolean installed;

	TransactionalTreeEditor(QueryModelNode original, ScopeAnalysis analysis) {
		this.original = original;
		originalParent = original.getParentNode();
		arena = analysis.arena();
		boundaryOrigin = arena.origin(original);
	}

	void install(QueryModelNode replacement) {
		if (installed) {
			throw new IllegalStateException("replacement already installed");
		}
		if (originalParent == null) {
			throw new IllegalStateException("a QueryRoot child is required as the transaction boundary");
		}
		this.replacement = replacement;
		registerCandidate(replacement);
		originalParent.replaceChildNode(original, replacement);
		installed = true;
	}

	private void registerCandidate(QueryModelNode candidate) {
		candidate.visit(new org.eclipse.rdf4j.query.algebra.helpers.AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode node) {
				if (arena.id(node) < 0) {
					int origin = arena.origin(node);
					arena.registerNewNode(node, origin < 0 ? boundaryOrigin : origin);
				}
				super.meetNode(node);
			}
		});
	}

	void rollback() {
		if (installed) {
			originalParent.replaceChildNode(replacement, original);
		}
		clear();
	}

	void commit() {
		clear();
	}

	private void clear() {
		replacement = null;
		installed = false;
	}
}

final class BoundaryContract {

	private static final int OBSERVABLE_FLAGS = FactFlags.HAS_GROUP | FactFlags.HAS_DISTINCT | FactFlags.HAS_REDUCED
			| FactFlags.HAS_ORDER
			| FactFlags.HAS_SLICE | FactFlags.HAS_SERVICE | FactFlags.HAS_LATERAL | FactFlags.HAS_EXISTS
			| FactFlags.HAS_VOLATILE_EXPR | FactFlags.HAS_EXTERNAL_EXPR | FactFlags.HAS_CORRELATION
			| FactFlags.SEQUENCE_SENSITIVE | FactFlags.MULTIPLICITY_SENSITIVE | FactFlags.NON_DUPLICABLE
			| FactFlags.NON_MOVABLE | FactFlags.HARD_REWRITE_BARRIER;

	private final int frame;
	private final int region;
	private final int environment;
	private final byte resultKind;
	private final int observableFlags;
	private final long fingerprint;
	private final EnumMap<SemanticMask, Set<String>> masks;

	private BoundaryContract(int frame, int region, int environment, byte resultKind, int observableFlags,
			long fingerprint, EnumMap<SemanticMask, Set<String>> masks) {
		this.frame = frame;
		this.region = region;
		this.environment = environment;
		this.resultKind = resultKind;
		this.observableFlags = observableFlags;
		this.fingerprint = fingerprint;
		this.masks = masks;
	}

	static BoundaryContract capture(ScopeAnalysis analysis, QueryModelNode node) {
		int nodeId = analysis.arena().id(node);
		FactIndex facts = analysis.facts();
		EnumMap<SemanticMask, Set<String>> masks = new EnumMap<>(SemanticMask.class);
		for (SemanticMask mask : SemanticMask.values()) {
			masks.put(mask, analysis.names(mask, node));
		}
		return new BoundaryContract(facts.frame(nodeId), facts.region(nodeId), facts.environment(nodeId),
				facts.resultKind(nodeId), facts.flags(nodeId) & OBSERVABLE_FLAGS, facts.fingerprint(nodeId), masks);
	}

	BoundaryDifference compare(BoundaryContract other) {
		// Fingerprints are deliberately only a precheck. Exact fields are compared even on equality.
		boolean fingerprintMatched = fingerprint == other.fingerprint;
		if (frame != other.frame) {
			return new BoundaryDifference("frame", frame, other.frame, fingerprintMatched);
		}
		if (region != other.region) {
			return new BoundaryDifference("region", region, other.region, fingerprintMatched);
		}
		if (environment != other.environment) {
			return new BoundaryDifference("environment", environment, other.environment, fingerprintMatched);
		}
		if (resultKind != other.resultKind) {
			return new BoundaryDifference("resultKind", resultKind, other.resultKind, fingerprintMatched);
		}
		if (observableFlags != other.observableFlags) {
			return new BoundaryDifference("observableFlags", observableFlags, other.observableFlags,
					fingerprintMatched);
		}
		for (Map.Entry<SemanticMask, Set<String>> entry : masks.entrySet()) {
			Set<String> after = other.masks.get(entry.getKey());
			if (!entry.getValue().equals(after)) {
				return new BoundaryDifference(entry.getKey().name(), entry.getValue(), after, fingerprintMatched);
			}
		}
		return null;
	}
}

record BoundaryDifference(String field, Object before, Object after, boolean fingerprintMatched) {
}

final class RewriteRejectedException extends IllegalStateException {

	private static final long serialVersionUID = 1L;

	private final BoundaryDifference difference;

	RewriteRejectedException(BoundaryDifference difference) {
		super("rewrite changed boundary " + difference.field() + " from " + difference.before() + " to "
				+ difference.after());
		this.difference = difference;
	}

	BoundaryDifference difference() {
		return difference;
	}
}
